import { useState } from 'react';

const faqs = [
  {
    question: 'Qui peut bénéficier de votre assurance taxi ?',
    answer: 'Nous assurons tous les profils : nouveaux chauffeurs, chauffeurs expérimentés, profils avec malus ou résiliation, jeune permis, etc. Notre réseau d\'assureurs partenaires nous permet de trouver une solution pour chaque situation.'
  },
  {
    question: 'Comment obtenir un devis rapide ?',
    answer: 'Remplissez notre formulaire en ligne en moins de 2 minutes. Vous recevrez un premier devis sous 24h par email. Notre équipe reste disponible pour vous accompagner dans votre choix.'
  },
  {
    question: 'Quelle est la différence entre RC Pro et assurance auto classique ?',
    answer: 'L\'assurance RC Pro (Responsabilité Civile Professionnelle) est obligatoire pour tout professionnel du transport. Elle couvre spécifiquement les dommages causés dans le cadre de votre activité professionnelle, ce qu\'excluent les assurances auto classiques.'
  },
  {
    question: 'Acceptez-vous les profils avec résiliation ou malus ?',
    answer: 'Oui, absolument. Nous avons des partenariats avec des assureurs spécialisés dans les profils difficiles. Même en cas de résiliation ou de malus important, nous trouvons généralement une solution.'
  },
  {
    question: 'Quels documents sont nécessaires pour la souscription ?',
    answer: 'Pour obtenir votre devis, vous aurez besoin de : votre permis de conduire, vos antecedentes d\'assurance (sinistres des 3 dernières années), et les documents de votre véhicule. Pour la souscription finale : pièce d\'identié, justificatif de domicile, KBIS pour les professionnels.'
  },
  {
    question: 'Puis-je changer d\'assurance en cours d\'année ?',
    answer: 'Oui, vous pouvez résilier votre contrat à chaque échéance annuelle (date d\'anniversaire du contrat). Certaines assurances permettent aussi la résiliation en cours d\'année sous conditions (vente du véhicule, changement de situation).'
  }
];

export default function FAQ() {
  const [openIndex, setOpenIndex] = useState(null);

  return (
    <section id="faq" className="py-20 bg-gray-50">
      <div className="max-w-3xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-14">
          <h2 className="text-3xl md:text-4xl font-bold text-gray-900">
            Questions <span className="text-blue-800">fréquentes</span>
          </h2>
          <p className="mt-4 text-gray-600 text-lg">
            Tout ce que vous devez savoir sur l'assurance taxi
          </p>
        </div>

        <div className="space-y-4">
          {faqs.map((faq, index) => (
            <div key={index} className="bg-white rounded-xl shadow-sm overflow-hidden">
              <button
                className="w-full px-6 py-5 text-left flex items-center justify-between"
                onClick={() => setOpenIndex(openIndex === index ? null : index)}
              >
                <span className="font-semibold text-gray-900 pr-4">{faq.question}</span>
                <span className={`text-2xl text-blue-800 transition-transform ${openIndex === index ? 'rotate-180' : ''}`}>
                  ▼
                </span>
              </button>
              {openIndex === index && (
                <div className="px-6 pb-5 text-gray-600">
                  {faq.answer}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
